// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
(function calculatedFieldValue(current) {
	var parentOuId = current.sys_id;
	var activeTaskCount;
	if(parentOuId != '' )
	{
		// STRY0074595
		if(current.u_external_flag==true){
			// find tasks flagged for extneral OUs
			activeTaskCount = new GlideAggregate("x_153465_discovert_route_task_instance");
			var orClause = activeTaskCount.addQuery("tasking_authority", parentOuId);
			orClause.addOrCondition('u_external_ou', parentOuId);
			activeTaskCount.addQuery("active", true);
			activeTaskCount.addAggregate("COUNT");
			activeTaskCount.query();
			if(activeTaskCount.next()){
				return activeTaskCount.getAggregate("COUNT");}
		}else{
			activeTaskCount = new GlideAggregate("x_153465_discovert_route_task_instance");
			activeTaskCount.addQuery("primary_assignee", parentOuId);
			activeTaskCount.addQuery("active", true);
			activeTaskCount.addAggregate("COUNT");
			activeTaskCount.query();
			if(activeTaskCount.next()){
				return activeTaskCount.getAggregate("COUNT");}
		}
	}
	return 0;

})(current);

(function calculatedFieldValue(current) {
	var parentOuId = current.sys_id;
	if(parentOuId != ''){
	var childOuCount = new GlideAggregate("x_153465_discovert_discover_office_hierarchy");
	childOuCount.addQuery("parent", parentOuId);
	childOuCount.addQuery("active", true);
	childOuCount.addAggregate("COUNT");
	childOuCount.query();
	if(childOuCount.next())
		return childOuCount.getAggregate("COUNT");
	}
	return 0;
})(current);

(function calculatedFieldValue(current) {
	var parentOuId = current.sys_id;
	if(parentOuId != ''){
	var ouMemberCount = new GlideAggregate("x_153465_discovert_discover_office_members");
	ouMemberCount.addQuery("discover_office_hierarchy", parentOuId);
	ouMemberCount.addAggregate("COUNT");
	ouMemberCount.query();
	if(ouMemberCount.next())
		return ouMemberCount.getAggregate("COUNT");
	}
	return 0;
})(current);

(function calculatedFieldValue(current) {
	// get all Global TA Members
	var ouMemberRecords = new GlideRecord("x_153465_discovert_discover_office_members");
	ouMemberRecords.addQuery("is_global_tasking_authority", true);
	ouMemberRecords.query();
	var ouMembers = '';
	// accumulate all global ta members
	while(ouMemberRecords.next()) {
		if(ouMembers === '') {
			ouMembers = ouMemberRecords.office_member.name;
		} else {
			ouMembers = ouMembers + "," + ouMemberRecords.office_member.name;
		}
	}
	// return accumulated members
	return ouMembers;

})(current);

(function calculatedFieldValue(current) {
	// STRY0074595
	var parentOuId = current.sys_id;
	if(parentOuId != ''){
		var ouContactCount = new GlideAggregate("x_153465_discovert_organizational_contacts");
		ouContactCount.addQuery('u_contact_ou', parentOuId);
		ouContactCount.addAggregate("COUNT");
		ouContactCount.query();
		if(ouContactCount.next())
			return ouContactCount.getAggregate("COUNT");
	}
	return 0;
})(current);
